package com.example.webviewbridge

import android.Manifest
import android.app.Activity
import android.content.Context
import android.content.Intent
import android.content.pm.PackageManager
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.provider.MediaStore
import android.webkit.JavascriptInterface
import android.webkit.ValueCallback
import android.webkit.WebChromeClient
import android.webkit.WebView
import android.webkit.WebViewClient
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import com.google.firebase.messaging.FirebaseMessaging
import org.json.JSONObject
import java.io.File
import java.io.IOException
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class WebViewBridgeActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private var filePathCallback: ValueCallback<Array<Uri>>? = null
    private var cameraPhotoUri: Uri? = null

    companion object {
        private const val CAMERA_PERMISSION_CODE = 100
        private const val STORAGE_PERMISSION_CODE = 101
        private const val NOTIFICATION_PERMISSION_CODE = 102
    }

    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val results = if (result.data == null || result.data?.data == null) {
                cameraPhotoUri?.let { arrayOf(it) }
            } else {
                arrayOf(result.data?.data!!)
            }
            filePathCallback?.onReceiveValue(results)
        } else {
            filePathCallback?.onReceiveValue(null)
        }
        filePathCallback = null
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        webView = WebView(this)
        setContentView(webView)
        
        setupWebView()
        
        webView.loadUrl("https://your-web-app-url.com")
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            setSupportZoom(true)
            builtInZoomControls = false
            useWideViewPort = true
            loadWithOverviewMode = true
        }

        webView.addJavascriptInterface(NativeBridge(this), "NativeBridge")
        
        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, url: String?): Boolean {
                return false
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                this@WebViewBridgeActivity.filePathCallback?.onReceiveValue(null)
                this@WebViewBridgeActivity.filePathCallback = filePathCallback

                val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                if (takePictureIntent.resolveActivity(packageManager) != null) {
                    val photoFile: File? = try {
                        createImageFile()
                    } catch (ex: IOException) {
                        null
                    }
                    
                    photoFile?.also {
                        cameraPhotoUri = FileProvider.getUriForFile(
                            this@WebViewBridgeActivity,
                            "${applicationContext.packageName}.fileprovider",
                            it
                        )
                        takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, cameraPhotoUri)
                    }
                }

                val contentSelectionIntent = Intent(Intent.ACTION_GET_CONTENT)
                contentSelectionIntent.addCategory(Intent.CATEGORY_OPENABLE)
                contentSelectionIntent.type = "image/*"

                val intentArray = arrayOf(takePictureIntent)

                val chooserIntent = Intent(Intent.ACTION_CHOOSER)
                chooserIntent.putExtra(Intent.EXTRA_INTENT, contentSelectionIntent)
                chooserIntent.putExtra(Intent.EXTRA_TITLE, "Select Image")
                chooserIntent.putExtra(Intent.EXTRA_INITIAL_INTENTS, intentArray)

                fileChooserLauncher.launch(chooserIntent)
                return true
            }
        }
    }

    @Throws(IOException::class)
    private fun createImageFile(): File {
        val timeStamp: String = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
        val storageDir: File? = getExternalFilesDir(android.os.Environment.DIRECTORY_PICTURES)
        return File.createTempFile(
            "JPEG_${timeStamp}_",
            ".jpg",
            storageDir
        )
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    inner class NativeBridge(private val context: Context) {

        @JavascriptInterface
        fun openCamera(callbackId: String) {
            (context as? Activity)?.runOnUiThread {
                if (checkCameraPermission()) {
                    triggerCameraCapture(callbackId)
                } else {
                    requestCameraPermission()
                }
            }
        }

        @JavascriptInterface
        fun saveToLocalStorage(key: String, value: String): Boolean {
            return try {
                val sharedPref = context.getSharedPreferences("WebViewBridgeStorage", Context.MODE_PRIVATE)
                with(sharedPref.edit()) {
                    putString(key, value)
                    commit()
                }
            } catch (e: Exception) {
                false
            }
        }

        @JavascriptInterface
        fun getFromLocalStorage(key: String): String? {
            val sharedPref = context.getSharedPreferences("WebViewBridgeStorage", Context.MODE_PRIVATE)
            return sharedPref.getString(key, null)
        }

        @JavascriptInterface
        fun removeFromLocalStorage(key: String): Boolean {
            return try {
                val sharedPref = context.getSharedPreferences("WebViewBridgeStorage", Context.MODE_PRIVATE)
                with(sharedPref.edit()) {
                    remove(key)
                    commit()
                }
            } catch (e: Exception) {
                false
            }
        }

        @JavascriptInterface
        fun clearLocalStorage(): Boolean {
            return try {
                val sharedPref = context.getSharedPreferences("WebViewBridgeStorage", Context.MODE_PRIVATE)
                with(sharedPref.edit()) {
                    clear()
                    commit()
                }
            } catch (e: Exception) {
                false
            }
        }

        @JavascriptInterface
        fun requestPushNotificationPermission(callbackId: String) {
            (context as? Activity)?.runOnUiThread {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                    if (ContextCompat.checkSelfPermission(
                            context,
                            Manifest.permission.POST_NOTIFICATIONS
                        ) == PackageManager.PERMISSION_GRANTED
                    ) {
                        subscribeToPushNotifications(callbackId)
                    } else {
                        ActivityCompat.requestPermissions(
                            context,
                            arrayOf(Manifest.permission.POST_NOTIFICATIONS),
                            NOTIFICATION_PERMISSION_CODE
                        )
                    }
                } else {
                    subscribeToPushNotifications(callbackId)
                }
            }
        }

        @JavascriptInterface
        fun getPushNotificationToken(callbackId: String) {
            FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val token = task.result
                    sendCallbackToWeb(callbackId, true, token)
                } else {
                    sendCallbackToWeb(callbackId, false, "Failed to get token")
                }
            }
        }

        @JavascriptInterface
        fun showToast(message: String) {
            (context as? Activity)?.runOnUiThread {
                Toast.makeText(context, message, Toast.LENGTH_SHORT).show()
            }
        }

        @JavascriptInterface
        fun getDeviceInfo(): String {
            val deviceInfo = JSONObject()
            deviceInfo.put("manufacturer", Build.MANUFACTURER)
            deviceInfo.put("model", Build.MODEL)
            deviceInfo.put("version", Build.VERSION.RELEASE)
            deviceInfo.put("sdkInt", Build.VERSION.SDK_INT)
            deviceInfo.put("appVersion", context.packageManager.getPackageInfo(context.packageName, 0).versionName)
            return deviceInfo.toString()
        }

        @JavascriptInterface
        fun shareContent(title: String, text: String, url: String) {
            (context as? Activity)?.runOnUiThread {
                val shareIntent = Intent().apply {
                    action = Intent.ACTION_SEND
                    type = "text/plain"
                    putExtra(Intent.EXTRA_SUBJECT, title)
                    putExtra(Intent.EXTRA_TEXT, "$text\n$url")
                }
                context.startActivity(Intent.createChooser(shareIntent, "Share via"))
            }
        }

        @JavascriptInterface
        fun vibrate(duration: Long) {
            (context as? Activity)?.runOnUiThread {
                val vibrator = ContextCompat.getSystemService(context, android.os.Vibrator::class.java)
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                    vibrator?.vibrate(
                        android.os.VibrationEffect.createOneShot(
                            duration,
                            android.os.VibrationEffect.DEFAULT_AMPLITUDE
                        )
                    )
                } else {
                    @Suppress("DEPRECATION")
                    vibrator?.vibrate(duration)
                }
            }
        }

        private fun subscribeToPushNotifications(callbackId: String) {
            FirebaseMessaging.getInstance().subscribeToTopic("all")
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        sendCallbackToWeb(callbackId, true, "Subscribed to notifications")
                    } else {
                        sendCallbackToWeb(callbackId, false, "Failed to subscribe")
                    }
                }
        }

        private fun sendCallbackToWeb(callbackId: String, success: Boolean, data: String) {
            (context as? Activity)?.runOnUiThread {
                val result = JSONObject()
                result.put("success", success)
                result.put("data", data)
                webView.evaluateJavascript(
                    "window.NativeBridgeCallbacks['$callbackId']($result);",
                    null
                )
            }
        }
    }

    private fun checkCameraPermission(): Boolean {
        return ContextCompat.checkSelfPermission(
            this,
            Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED
    }

    private fun requestCameraPermission() {
        ActivityCompat.requestPermissions(
            this,
            arrayOf(Manifest.permission.CAMERA),
            CAMERA_PERMISSION_CODE
        )
    }

    private fun triggerCameraCapture(callbackId: String) {
        val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
        if (takePictureIntent.resolveActivity(packageManager) != null) {
            val photoFile: File? = try {
                createImageFile()
            } catch (ex: IOException) {
                null
            }
            
            photoFile?.also {
                val photoUri = FileProvider.getUriForFile(
                    this,
                    "${applicationContext.packageName}.fileprovider",
                    it
                )
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoUri)
                startActivityForResult(takePictureIntent, 1001)
            }
        }
    }

    override fun onRequestPermissionsResult(
        requestCode: Int,
        permissions: Array<out String>,
        grantResults: IntArray
    ) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)
        when (requestCode) {
            CAMERA_PERMISSION_CODE -> {
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    Toast.makeText(this, "Camera permission granted", Toast.LENGTH_SHORT).show()
                } else {
                    Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show()
                }
            }
            NOTIFICATION_PERMISSION_CODE -> {
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    Toast.makeText(this, "Notification permission granted", Toast.LENGTH_SHORT).show()
                } else {
                    Toast.makeText(this, "Notification permission denied", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }
}